perspectives.style:
@settings {
  template: stakeholder;
}

element {
  color: #ffffff;
  size: scale("influence", 20, 100);
  min-size: 20;
  image-fit: contain;
  border-width: 4;
  border-color: #9aa4b2;
  font-size: 13;
}

element["element type"="Person"]  { border-color: #ff6b6b; image-fit: cover; }
element["element type"="Project"] { border-color: #4ecdc4; image-fit: contain; }
element["element type"="Tag"]     { border-color: #f4a261; }

connection { color: #b0b7c0; width: 1.5; arrow-size: 6; }

@settings {
  template: stakeholder;
  colorBy: "born";
}

element {
  size: scale("influence", 20, 100);
  min-size: 20;
  border-width: 3;
  image-fit: contain;
  font-size: 13;
}
element["element type"="Person"]  { image-fit: cover; }
element["element type"="Project"] { opacity: 0.12; }

connection { color: #c7ccd4; width: 1.2; }

